 public static Set<String> generateWords(String input, char mandatoryChar) {
        Set<String> results = new HashSet<>();
        String remainingChars = input.replace(String.valueOf(mandatoryChar), "");  // remove mandatory char

        // Generate all combinations of 3+ length without the mandatory char
        generateCombinations(remainingChars, "", results);

        // For each combination, insert the mandatory character in all possible positions
        Set<String> finalResults = new HashSet<>();
        for (String word : results) {
            for (int i = 0; i <= word.length(); i++) {
                String withMandatoryChar = word.substring(0, i) + mandatoryChar + word.substring(i);
                if (withMandatoryChar.length() == 4) {  // Check if length is 4
                    finalResults.add(withMandatoryChar);
                }
            }
        }

        return finalResults;
    }

    //method to generate all combinations of 3 letters
    private static void generateCombinations(String input, String prefix, Set<String> results) {
        if (prefix.length() == 3) {
            results.add(prefix);
            return;
        }

        for (int i = 0; i < input.length(); i++) {
            generateCombinations(input.substring(i + 1), prefix + input.charAt(i), results);
        }
    }
