This can be done by generating combinations of length 4-7 and checking whether those combinations are valid(includes mandatory character or not). If yes, push them in the final ans otherwise skip.
I tried a different approach as well, I generated all the 6 char long words with recursive backtracking. Now in this list we can iterate over each word and generate subWords of length 3-6 and insert our mandatory character at all possible positions of these subWords. This approach helps by skipping redundant work of generating permutations for each length from 4-7. Not sure if this really is better but implemented it anyways. 

Here is the javaScript code - 
```javaScript
function generateWords(chars) {
    const [mandatoryCh, ...restChars] = chars.split('');
    const allUniqueWords = new Set();
    const words = [];

    // Step 1: Generate all 6-character combinations
    genCombinations(restChars, words, [], 6, 0);

    // Step 2: Add mandatory character and generate valid substrings
    for (let word of words) {
        addMandatoryChar(word, mandatoryCh, allUniqueWords, 4, 7);
    }

    return Array.from(allUniqueWords).sort();
}

function genCombinations(chars, words, currWord, len, index) {
    if (currWord.length === len) {
        words.push(currWord.join(''));
        return;
    }
    if (index >= chars.length) return;

    // Include the current character
    currWord.push(chars[index]);
    genCombinations(chars, words, currWord, len, index + 1);

    // Exclude the current character
    currWord.pop();
    genCombinations(chars, words, currWord, len, index + 1);
}

function addMandatoryChar(word, mandatoryChar, uniqueWords, minLen, maxLen) {
    for (let len = minLen; len <= maxLen; len++) {
        for (let start = 0; start <= word.length - len + 1; start++) {
            const subWord = word.slice(start, start + len - 1);
            for (let i = 0; i <= subWord.length; i++) {
                const newWord = subWord.slice(0, i) + mandatoryChar + subWord.slice(i);
                uniqueWords.add(newWord);
            }
        }
    }
}

